# LIS — O(n log n) time, O(n) space using patience sorting
# KEY INSIGHT: maintain 'tails' array where tails[i] = smallest tail of
# all increasing subsequences of length i+1

import bisect

def lengthOfLIS(nums):
    tails = []  # tails[i] = smallest ending element of LIS of length i+1

    for num in nums:
        pos = bisect.bisect_left(tails, num)  # find leftmost pos where tails[pos] >= num

        if pos == len(tails):
            tails.append(num)  # extend LIS
        else:
            tails[pos] = num   # replace to maintain smallest possible tail

    return len(tails)

# O(n^2) DP version (easier to understand):
def lengthOfLIS_dp(nums):
    dp = [1] * len(nums)
    for i in range(1, len(nums)):
        for j in range(i):
            if nums[j] < nums[i]:
                dp[i] = max(dp[i], dp[j] + 1)
    return max(dp)
